import re, zlib
data = open('webfetch-1781187288500-5r7j5v.pdf','rb').read()
chunks=[]
for m in re.finditer(rb'stream\r?\n(.*?)\r?\nendstream', data, re.DOTALL):
    try: chunks.append(zlib.decompress(m.group(1)))
    except: pass
full=b'\n'.join(chunks)
# Grab all parenthesized strings AND hex strings, join, strip kerning
parts=[]
for m in re.finditer(rb'\((?:[^()\\\\]|\\\\.)*\)', full):
    parts.append(m.group(0)[1:-1])
out=b''.join(parts).decode('latin-1')
out=re.sub(r'\s+',' ',out)
for kw in ['eleven','405','30,000','30000','MMLU','MT-Bench','MBPP','HellaSwag','Hellaswag','Winogrande','GSM8K','GSM-8','ARC','11 LLM','11 different','11 models','eight','seven','six']:
    for m in list(re.finditer(re.escape(kw), out))[:2]:
        i=m.start()
        print('['+kw+']', repr(out[max(0,i-70):i+90]))
" 2>&1 | head -60","description":"Robust text extraction from RouterBench PDF"}

